function normalizeStatusUpdate(row){const id=norm(row.Id)||norm(row["Id"])||norm(row.ID)||norm(row["ID"]);const sit=field(row,"Situação","Situacao","Status","Resultado","Resultado Da Análise","Resultado Da Analise");if(!id||!sit)return null;return {Id:id,"Situação":sit,"Resultado Da Análise":sit,__aglStatusOnly:true};}function supplementalAglRow(row){const sit=field(row,"Situação","Situacao","Resultado Da Análise","Resultado Da Analise")||"Reprovado";return {Id:norm(row.Id)||norm(row["Id"]),"Situação":sit,"Resultado Da Análise":sit,"Empreendimento":"AGL - Base complementar","Imobiliária":AGL_COMPLEMENT_TEAM_BY_ID[norm(row.Id)||norm(row["Id"])]||"Complemento AGL","Corretor":"","Cliente":"Complemento do anexo","Aprovação":sit==="Aprovado"?"Sim":"Não","Data de Aprovação":"","Renda Total":"","Valor Aprovado":"0,00","Valor Subsídio":"0,00","Valor total":"0,00","Prazo do Financiamento":"","Situação anterior":"","Momento Do Pré-Cadastro":"","Data Resposta Da Análise":"27/05/2026","Tipo da Renda":""};}function mergeStatusIntoRow(current,update){return {...current,"Situação":update["Situação"],"Resultado Da Análise":update["Resultado Da Análise"]};}function applyDataCorrections(rows){const out=rows.slice(),byId=new Map(out.map((r,i)=>[norm(r.Id)||norm(r["Id"]),i]));[...FORCE_APPROVED_ROWS,...FORCE_CONDITIONED_ROWS,...FORCE_REJECTED_ROWS,...AGL_STATUS_UPDATES.map(normalizeStatusUpdate).filter(Boolean)].forEach(r=>{const id=norm(r.Id);if(byId.has(id)){out[byId.get(id)]=r.__aglStatusOnly?mergeStatusIntoRow(out[byId.get(id)],r):{...out[byId.get(id)],...r};}else{const row=r.__aglStatusOnly?supplementalAglRow(r):r;byId.set(id,out.length);out.push(row);}});return out;}
