function loadData(){clearOldDashboardStorage();try{const s=localStorage.getItem(STORAGE_KEY);if(s){const saved=JSON.parse(s);if(Array.isArray(saved)&&saved.length)return applyDataCorrections(saved);localStorage.removeItem(STORAGE_KEY);}}catch(e){try{localStorage.removeItem(STORAGE_KEY)}catch(_){}}return applyDataCorrections(Array.isArray(INITIAL_DATA)?INITIAL_DATA:[]);}
function saveData(){if(Array.isArray(data)&&data.length)localStorage.setItem(STORAGE_KEY,JSON.stringify(data));}
function norm(v){return (v??'').toString().trim();}
function keyNorm(v){return norm(v).normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();}
function field(row,...names){for(const name of names){const direct=norm(row[name]);if(direct)return direct;}const wanted=names.map(keyNorm);for(const k of Object.keys(row)){if(wanted.includes(keyNorm(k))){const val=norm(row[k]);if(val)return val;}}return '';}
function classificaResultado(txt){const up=norm(txt).toUpperCase();if(up.includes('APROV'))return 'Aprovado';if(up.includes('COND'))return 'Condicionado';if(up.includes('REPROV')||up.includes('NEGAD')||up.includes('RECUS'))return 'Reprovado';return '';}
function classificaFiltro(txt){const up=norm(txt).toUpperCase();if(up.includes('COND')&&up.includes('PEND'))return 'Condicionado Pendente';return classificaResultado(txt);}
function analiseResultado(row){return field(row,'Resultado da Análise','Resultado Da Análise','Resultado','Análise','Analise');}
function resultado(row){const situacao=field(row,'Situação'),base=keyNorm(situacao)==='em reserva'?analiseResultado(row):situacao;return classificaResultado(base)||'Reprovado';}
function resultadoFiltro(row){const situacao=field(row,'Situação'),base=keyNorm(situacao)==='em reserva'?analiseResultado(row):situacao;return classificaFiltro(base)||resultado(row);}
function resultadoDisplay(row){const situacao=field(row,'Situação'),base=keyNorm(situacao)==='em reserva'?analiseResultado(row):situacao;return norm(base)||resultado(row);}
function parseDateBR(s){s=norm(s);const m=s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);if(!m)return null;return {d:m[1].padStart(2,'0'),m:m[2].padStart(2,'0'),y:m[3],label:`${m[1].padStart(2,'0')}/${m[2].padStart(2,'0')}/${m[3]}`};}
function dataResposta(row){return field(row,'Data Resposta Da Análise','Data Resposta Da Analise','Data Resposta','Data Resp','Dt Resposta','Data de Aprovação','Data de Aprovacao');}
function dateObj(row){return parseDateBR(dataResposta(row));}
function uniq(arr){return [...new Set(arr.filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR',{numeric:true}));}
function getSelected(id){return Array.from(document.getElementById(id).selectedOptions).map(o=>o.value).filter(Boolean);}
function selectedHas(id,val){const a=getSelected(id);return a.length===0||a.includes(val);}
function ensureFilterUi(id){const el=document.getElementById(id),box=el.closest('.filter');let btn=box.querySelector('.filterToggle'),menu=box.querySelector('.filterMenu');if(!btn){btn=document.createElement('button');btn.type='button';btn.className='filterToggle';btn.addEventListener('click',ev=>{ev.stopPropagation();openFilterId=openFilterId===id?'':id;document.querySelectorAll('.filter').forEach(f=>f.classList.remove('open'));if(openFilterId)box.classList.add('open');});el.insertAdjacentElement('afterend',btn);}if(!menu){menu=document.createElement('div');menu.className='filterMenu';menu.addEventListener('click',ev=>ev.stopPropagation());btn.insertAdjacentElement('afterend',menu);}box.classList.toggle('open',openFilterId===id);return {btn,menu};}
function updateFilterSummary(id){const {btn}=ensureFilterUi(id),sel=getSelected(id);btn.textContent=sel.length?sel.length===1?sel[0]:sel.length+' selecionados':'Todos';btn.title=sel.length?sel.join(' | '):'Todos';}
function renderFilterChoices(id){const el=document.getElementById(id),{menu}=ensureFilterUi(id);const opts=Array.from(el.options);menu.innerHTML=opts.length?opts.map((o,i)=>`<label class="filterOption"><input type="checkbox" data-filter-choice="${escapeAttr(id)}" data-option-index="${i}" ${o.selected?'checked':''}> <span>${escapeHtml(o.textContent)}</span></label>`).join(''):'<div class="filterEmpty">Sem opções</div>';menu.querySelectorAll('[data-filter-choice]').forEach(ch=>ch.addEventListener('change',()=>{const opt=el.options[Number(ch.dataset.optionIndex)];if(opt)opt.selected=ch.checked;openFilterId=id;selectedImob='';selectedBarImob='';detail.style.display='none';render();}));updateFilterSummary(id);}
function fillMulti(id,vals){const el=document.getElementById(id);const cur=getSelected(id);el.innerHTML=vals.map(v=>`<option value="${escapeAttr(v)}">${escapeHtml(v)}</option>`).join('');Array.from(el.options).forEach(o=>{if(cur.includes(o.value))o.selected=true;});renderFilterChoices(id);}
function selectOnly(id,values){const wanted=new Set(values);Array.from(document.getElementById(id).options).forEach(o=>o.selected=wanted.has(o.value));renderFilterChoices(id);}
function applyDefaultAprovadosView(){if(localStorage.getItem(DEFAULT_FILTER_KEY))return;selectOnly('fRegiao',['AGL']);selectOnly('fAno',['2026']);selectOnly('fMes',['05 - Maio']);selectOnly('fAnalise',[]);localStorage.setItem(DEFAULT_FILTER_KEY,'1');}
function region(row){const emp=norm(row['Empreendimento']).toUpperCase();const sigla=(emp.match(/^([A-Z]{3})/)||[])[1]||'';if(sigla==='AGL')return 'AGL';if(sigla==='FSA')return 'FSA';if(sigla==='CAT')return 'CAT';return 'Outras';}
function initFilters(){fillMulti('fRegiao',['AGL','FSA','CAT']);fillMulti('fEmp',uniq(data.map(r=>norm(r['Empreendimento']))));fillMulti('fImob',uniq(data.map(r=>norm(r['Imobiliária']))));fillMulti('fAnalise',['Aprovado','Condicionado','Condicionado Pendente','Reprovado']);fillMulti('fCorretor',uniq(data.map(r=>norm(r['Corretor']))));fillMulti('fAno',Array.from({length:7},(_,i)=>String(2024+i)));fillMulti('fMes',['01 - Janeiro','02 - Fevereiro','03 - Março','04 - Abril','05 - Maio','06 - Junho','07 - Julho','08 - Agosto','09 - Setembro','10 - Outubro','11 - Novembro','12 - Dezembro']);fillMulti('fDia',Array.from({length:31},(_,i)=>String(i+1).padStart(2,'0')));}
function filtered(){return data.filter(r=>{const dt=dateObj(r)||{};const mes=dt.m?({'01':'01 - Janeiro','02':'02 - Fevereiro','03':'03 - Março','04':'04 - Abril','05':'05 - Maio','06':'06 - Junho','07':'07 - Julho','08':'08 - Agosto','09':'09 - Setembro','10':'10 - Outubro','11':'11 - Novembro','12':'12 - Dezembro'}[dt.m]):'';return selectedHas('fRegiao',region(r))&&selectedHas('fEmp',norm(r['Empreendimento']))&&selectedHas('fImob',norm(r['Imobiliária']))&&selectedHas('fAnalise',resultadoFiltro(r))&&selectedHas('fCorretor',norm(r['Corretor']))&&selectedHas('fAno',dt.y||'')&&selectedHas('fMes',mes)&&selectedHas('fDia',dt.d||'');});}
function countByResult(rows){const c={Aprovado:0,Condicionado:0,Reprovado:0};rows.forEach(r=>c[resultado(r)]++);return c;}
function moneyToNumber(v){v=norm(v).replace(/R\$|\s/g,''); if(!v)return 0; return Number(v.replace(/\./g,'').replace(',','.'))||0;}
function formatMoney(n){return n.toLocaleString('pt-BR',{style:'currency',currency:'BRL',maximumFractionDigits:0});}
function imobName(row){return norm(row['Imobiliária'])||'Sem imobiliária';}function teamName(row){const raw=imobName(row),k=keyNorm(raw);if(k==='canal virtual 1'||k==='canal virtual 3')return 'Canal 1';if(k==='canal virtual 2')return 'Canal 2';if(k==='equipe propria agl')return 'Equipe própria 1';if(k==='equipe propria 2 agl')return 'Equipe própria 2';if(k==='equipe propria 3 agl')return 'Equipe própria 3';if(k==='imobiliarias agl')return 'Imob';return raw;}function teamRows(name,rows){return rows.filter(r=>teamName(r)===name&&!(name==='Imob'&&resultado(r)==='Reprovado'));}
function sortImobNames(names){return names.slice().sort((a,b)=>a.localeCompare(b,'pt-BR',{numeric:true,sensitivity:'base'}));}
function render(){initFilters();applyDefaultAprovadosView();const rows=filtered();const c=countByResult(rows);kTotal.textContent=rows.length;kAprov.textContent=c.Aprovado;kCond.textContent=c.Condicionado;kRep.textContent=c.Reprovado;const vals=rows.map(r=>moneyToNumber(r['Valor total'])).filter(v=>v>0);kGarantidos.textContent=formatMoney(vals.length?vals.reduce((a,b)=>a+b,0)/vals.length:0);drawPie(c);drawBar(rows);renderMoments(rows);renderCards(rows);if(selectedBarImob)renderBrokerBreakdown(selectedBarImob,rows);else brokerBreakdown.classList.remove('open');if(selectedImob)renderDetail(selectedImob,rows);}
function drawPie(c){const can=pie,ctx=can.getContext('2d'),w=can.width=can.offsetWidth*2,h=can.height=can.offsetHeight*2;ctx.clearRect(0,0,w,h);const total=c.Aprovado+c.Condicionado+c.Reprovado;pieTotalBelow.textContent='Total: '+total;const cx=w*.48,cy=h*.47,r=Math.min(w,h)*.34;let start=-Math.PI/2;['Aprovado','Condicionado','Reprovado'].forEach(k=>{const val=c[k],ang=total?val/total*Math.PI*2:0;ctx.beginPath();ctx.moveTo(cx,cy);ctx.arc(cx,cy,r,start,start+ang);ctx.closePath();ctx.fillStyle=COLORS[k];ctx.fill();if(val>0){const mid=start+ang/2;const lx=cx+Math.cos(mid)*r*.68;const ly=cy+Math.sin(mid)*r*.68;const pct=total?Math.round(val/total*1000)/10:0;ctx.fillStyle=k==='Condicionado'?'#111':'#fff';ctx.font='bold 22px Segoe UI';ctx.textAlign='center';ctx.textBaseline='middle';ctx.shadowColor='rgba(0,0,0,.45)';ctx.shadowBlur=5;ctx.fillText(val,lx,ly-12);ctx.font='bold 16px Segoe UI';ctx.fillText(String(pct).replace('.',',')+'%',lx,ly+14);ctx.shadowBlur=0;}start+=ang;});}
function roundRect(ctx,x,y,w,h,r){if(h<=0)return;r=Math.min(r,w/2,h/2);ctx.beginPath();ctx.moveTo(x+r,y);ctx.arcTo(x+w,y,x+w,y+h,r);ctx.arcTo(x+w,y+h,x,y+h,0);ctx.arcTo(x,y+h,x,y,0);ctx.arcTo(x,y,x+w,y,r);ctx.closePath();}
function wrapLabel(ctx,text,x,y,maxWidth,lineHeight){let words=text.split(/\s+/),line='',lines=[];words.forEach(word=>{let test=line?line+' '+word:word;if(ctx.measureText(test).width>maxWidth&&line){lines.push(line);line=word}else line=test});lines.push(line);lines.slice(0,2).forEach((l,i)=>ctx.fillText(l,x,y+i*lineHeight));}
function drawBar(rows){const can=bar,ctx=can.getContext('2d'),scale=2,w=can.width=can.offsetWidth*scale,h=can.height=can.offsetHeight*scale;ctx.clearRect(0,0,w,h);barClickAreas=[];const groups=sortImobNames(uniq(rows.map(teamName))).map(name=>({name,c:countByResult(teamRows(name,rows))}));const max=Math.max(1,...groups.map(g=>g.c.Aprovado+g.c.Condicionado+g.c.Reprovado));const padL=62,padB=82,padT=24,padR=22,chartW=w-padL-padR,chartH=h-padT-padB;ctx.strokeStyle='rgba(255,255,255,.12)';ctx.fillStyle='#dbe8f5';ctx.font='20px Segoe UI';for(let i=0;i<=5;i++){const y=padT+chartH-chartH*i/5;ctx.beginPath();ctx.moveTo(padL,y);ctx.lineTo(w-padR,y);ctx.stroke();ctx.fillText(Math.round(max*i/5),16,y+7)}groups.forEach((g,i)=>{const total=g.c.Aprovado+g.c.Condicionado+g.c.Reprovado;const slot=chartW/groups.length,bw=Math.min(82,slot*.58),x=padL+i*slot+slot/2-bw/2;let y=padT+chartH;['Aprovado','Condicionado','Reprovado'].forEach(k=>{const bh=chartH*(g.c[k]/max);y-=bh;ctx.fillStyle=COLORS[k];roundRect(ctx,x,y,bw,bh,k==='Reprovado'?10:0);ctx.fill();if(g.c[k]>0&&bh>22){ctx.fillStyle=k==='Condicionado'?'#111':'#fff';ctx.font='bold 17px Segoe UI';ctx.textAlign='center';ctx.fillText(g.c[k],x+bw/2,y+bh/2+6);}});barClickAreas.push({name:g.name,x:x/scale,y:Math.max(0,(y-22)/scale),w:bw/scale,h:(padT+chartH-y+48)/scale});ctx.fillStyle='#fff';ctx.font='bold 18px Segoe UI';ctx.textAlign='center';ctx.fillText(total,x+bw/2,y-8);ctx.save();ctx.translate(x+bw/2,h-56);ctx.rotate(-.16);ctx.font='600 15px Segoe UI';wrapLabel(ctx,g.name,0,0,slot*.9,18);ctx.restore();});}
function renderMoments(rows){const map={};if(getSelected('fRegiao').includes('AGL')){Object.values(MOMENTO_REFERENCIA_BY_ID).forEach(momento=>{map[momento]=(map[momento]||0)+1;});}else{rows.forEach(r=>{const st=norm(r['Situação']);if(st!=='Aprovado'&&st!=='Condicionado')return;const momento=norm(r['Momento Do Pré-Cadastro'])||'Sem preenchimento';map[momento]=(map[momento]||0)+1;});}const total=Object.values(map).reduce((a,b)=>a+b,0)||1;const sorted=Object.entries(map).sort((a,b)=>b[1]-a[1]);momentTable.innerHTML='<div class="momentRow head"><div>Momento</div><div>Total</div><div>%</div></div>'+sorted.map(([k,v])=>`<div class="momentRow"><div>${escapeHtml(k)}</div><div>${v}</div><div>${String(Math.round(v/total*1000)/10).replace('.',',')}%</div></div>`).join('');}function renderCards(rows){const groups=sortImobNames(uniq(rows.map(teamName)));cards.innerHTML=groups.map(name=>{const rr=teamRows(name,rows),c=countByResult(rr);return `<div class="imobCard" onclick="selectedImob='${escapeAttr(name)}';detailSort={key:'',dir:''};renderDetail(selectedImob, filtered());document.getElementById('detail').scrollIntoView({behavior:'smooth'});"><h4>${escapeHtml(name)}</h4><div class="imobStats"><span>Total <b>${rr.length}</b></span><span><i class="statDot" style="background:${COLORS.Aprovado}"></i><b>${c.Aprovado}</b></span><span><i class="statDot" style="background:${COLORS.Condicionado}"></i><b>${c.Condicionado}</b></span><span><i class="statDot" style="background:${COLORS.Reprovado}"></i><b>${c.Reprovado}</b></span></div></div>`;}).join('');}
function renderBrokerBreakdown(name,rows){const rr=teamRows(name,rows);const brokers=uniq(rr.map(r=>norm(r['Corretor'])||'Sem corretor')).map(cor=>{const br=rr.filter(r=>(norm(r['Corretor'])||'Sem corretor')===cor),c=countByResult(br);return {cor,total:br.length,c};}).sort((a,b)=>b.total-a.total||a.cor.localeCompare(b.cor,'pt-BR'));brokerBreakdown.classList.add('open');brokerBreakdown.innerHTML=`<div class="brokerBreakdownHeader"><h3>${escapeHtml(name)} por corretor</h3><button class="iconBtn" type="button" onclick="clearBrokerBreakdown()" title="Voltar">↩</button></div><div class="brokerGrid">${brokers.map(b=>`<div class="brokerCard"><strong>${escapeHtml(b.cor)}</strong><div class="brokerMini"><span>Total <b>${b.total}</b></span><span>A <b>${b.c.Aprovado}</b></span><span>C <b>${b.c.Condicionado}</b></span><span>R <b>${b.c.Reprovado}</b></span></div></div>`).join('')}</div>`;}
function clearBrokerBreakdown(){selectedBarImob='';brokerBreakdown.classList.remove('open');brokerBreakdown.innerHTML='';bar.scrollIntoView({behavior:'smooth',block:'center'});}
function cleanPrazo(v){return norm(v).replace(/\s*meses\s*/ig,'').trim();}
function detailColumns(){return [{h:'ID',key:'Id'},{h:'Situação',key:'Situação'},{h:'Aprovação',key:'Aprovação'},{h:'Data de Aprovação',key:'Data de Aprovação'},{h:'Cliente',key:'Cliente'},{h:'Renda Total',key:'Renda Total'},{h:'Empreendimento',key:'Empreendimento'},{h:'Corretor',key:'Corretor'},{h:'Imobiliária',key:'Imobiliária'},{h:'Valor aprovado',key:'Valor Aprovado'},{h:'Valor de subsídio',key:'Valor Subsídio'},{h:'Valor Total',key:'Valor total'},{h:'Prazo de financiamento',key:'Prazo do Financiamento'},{h:'Situação anterior',key:'Situação anterior'},{h:'Momento do pré-cadastro',key:'Momento Do Pré-Cadastro'},{h:'Data da Resposta',key:'Data Resposta Da Análise'},{h:'Tipo de Renda',key:'Tipo da Renda'},{h:'Resultado da análise',key:'Resultado Da Análise'}];}
function valueForSort(r,key){if(key==='Prazo do Financiamento')return Number(cleanPrazo(r[key]).replace(/\D/g,''))||0;if(key.includes('Valor')||key==='Renda Total')return moneyToNumber(r[key]);const d=parseDateBR(r[key]);if(d)return d.y+d.m+d.d;return norm(r[key]).toLocaleLowerCase('pt-BR');}
function sortedRows(rows){if(!detailSort.key||!detailSort.dir)return rows.slice();return rows.slice().sort((a,b)=>{const av=valueForSort(a,detailSort.key),bv=valueForSort(b,detailSort.key);const cmp=typeof av==='number'&&typeof bv==='number'?av-bv:String(av).localeCompare(String(bv),'pt-BR',{numeric:true});return detailSort.dir==='asc'?cmp:-cmp;});}
function setDetailSort(key,dir){detailSort={key,dir};if(selectedImob)renderDetail(selectedImob,filtered());}
function resetDetailSort(){detailSort={key:'',dir:''};if(selectedImob)renderDetail(selectedImob,filtered());}
function closeDetail(){selectedImob='';detailSort={key:'',dir:''};detail.style.display='none';detail.innerHTML='';document.querySelector('.main').scrollIntoView({behavior:'smooth'});}
function sortHeader(col){const up=detailSort.key===col.key&&detailSort.dir==='asc'?' active':'',down=detailSort.key===col.key&&detailSort.dir==='desc'?' active':'';return `<th>${escapeHtml(col.h)}<span class="sortTools"><button class="sortBtn${up}" type="button" onclick="setDetailSort('${escapeAttr(col.key)}','asc')" title="Classificar crescente">↑</button><button class="sortBtn${down}" type="button" onclick="setDetailSort('${escapeAttr(col.key)}','desc')" title="Classificar decrescente">↓</button><button class="sortBtn" type="button" onclick="resetDetailSort()" title="Voltar ao normal">↺</button></span></th>`;}
function renderDetail(name,rows){const rr=sortedRows(teamRows(name,rows));detail.style.display='block';const cols=detailColumns();detail.innerHTML=`<div class="detailHeader"><h3 class="detailTitle">${escapeHtml(name)} — ${rr.length} registros</h3><button class="iconBtn" type="button" onclick="closeDetail()" title="Voltar">↩</button></div><div class="tableWrap"><table><thead><tr>${cols.map(sortHeader).join('')}</tr></thead><tbody>${rr.map(r=>`<tr>${cols.map(col=>{const raw=col.key==='Prazo do Financiamento'?cleanPrazo(r[col.key]):col.key==='Momento Do Pré-Cadastro'?(norm(r[col.key])||'Sem preenchimento'):norm(r[col.key]);return col.key==='Resultado Da Análise'?`<td><span class="pill ${resultado(r)}">${escapeHtml(resultadoDisplay(r))}</span></td>`:`<td>${escapeHtml(raw)}</td>`;}).join('')}</tr>`).join('')}</tbody></table></div>`;}
function csvDelimiter(text){const first=(text.split(/\r?\n/).find(l=>l.trim())||""),count=ch=>{let n=0,q=false;for(let i=0;i<first.length;i++){const c=first[i],nx=first[i+1];if(c==="\""){if(q&&nx==="\"")i++;else q=!q;}else if(c===ch&&!q)n++;}return n;};const scored=[[";",count(";")],[",",count(",")],["\t",count("\t")]].sort((a,b)=>b[1]-a[1]);return scored[0][1]?scored[0][0]:";";}
function isStatusOnlyAttachment(rows){if(!Array.isArray(rows)||!rows.length)return false;const keys=Object.keys(rows[0]).map(keyNorm);return keys.includes("id")&&keys.some(k=>k==="situacao"||k==="status"||k==="resultado"||k==="resultado da analise")&&!keys.includes("empreendimento");}function normalizeImportedRows(rows){if(!isStatusOnlyAttachment(rows))return rows;return rows.map(normalizeStatusUpdate).filter(Boolean);}function parseCSV(text){const sep=csvDelimiter(text),rows=[];let row=[],cell="",q=false;for(let i=0;i<text.length;i++){let ch=text[i],n=text[i+1];if(ch==="\""){if(q&&n==="\""){cell+="\"";i++}else q=!q}else if(ch===sep&&!q){row.push(cell);cell=""}else if((ch==="\n"||ch==="\r")&&!q){if(ch==="\r"&&n==="\n")i++;row.push(cell);if(row.some(x=>x.trim()!==""))rows.push(row);row=[];cell=""}else cell+=ch;}row.push(cell);if(row.some(x=>x.trim()!==""))rows.push(row);if(!rows.length)return [];const headers=rows.shift().map(h=>h.replace(/^\uFEFF/,"").trim());const parsed=rows.map(r=>{const o={};headers.forEach((h,i)=>o[h]=norm(r[i]));return o;}).filter(r=>norm(r.Id)||norm(r["Id"])||norm(r.ID)||norm(r["ID"])||Object.values(r).some(norm));return normalizeImportedRows(parsed);}
function mergeNew(newRows){if(!Array.isArray(newRows)||!newRows.length){alert('O anexo não trouxe registros válidos.');return;}let byId=new Map(data.map((r,i)=>[norm(r.Id)||norm(r['Id'])||JSON.stringify(r),i]));let added=0,updated=0;newRows.forEach(r=>{const id=norm(r.Id)||norm(r['Id'])||JSON.stringify(r);if(byId.has(id)){data[byId.get(id)]=r.__aglStatusOnly?mergeStatusIntoRow(data[byId.get(id)],r):{...data[byId.get(id)],...r};updated++;}else{const row=r.__aglStatusOnly?supplementalAglRow(r):r;byId.set(id,data.length);data.push(row);added++;}});saveData();selectedImob='';selectedBarImob='';detail.style.display='none';statusLine.textContent=`Último anexo: ${added} novos e ${updated} atualizados. Base atual: ${data.length} registros.`;render();}
function escapeHtml(s){return norm(s).replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m]));}function escapeAttr(s){return escapeHtml(s).replace(/'/g,'&#39;');}
['fRegiao','fEmp','fImob','fAno','fMes','fDia','fAnalise','fCorretor'].forEach(id=>document.getElementById(id).addEventListener('change',()=>{selectedImob='';selectedBarImob='';detail.style.display='none';render();}));
document.querySelectorAll('[data-clear]').forEach(btn=>btn.addEventListener('click',ev=>{ev.stopPropagation();const el=document.getElementById(btn.dataset.clear);Array.from(el.options).forEach(o=>o.selected=false);openFilterId='';selectedImob='';selectedBarImob='';detail.style.display='none';render();}));
document.addEventListener('click',ev=>{if(!ev.target.closest('.filter')){openFilterId='';document.querySelectorAll('.filter').forEach(f=>f.classList.remove('open'));}});
bar.addEventListener('click',ev=>{const rect=bar.getBoundingClientRect(),x=ev.clientX-rect.left,y=ev.clientY-rect.top;const hit=barClickAreas.find(a=>x>=a.x&&x<=a.x+a.w&&y>=a.y&&y<=a.y+a.h);if(hit){selectedBarImob=hit.name;renderBrokerBreakdown(hit.name,filtered());brokerBreakdown.scrollIntoView({behavior:'smooth',block:'nearest'});}});
fileInput.addEventListener('change',e=>{const f=e.target.files[0];if(!f)return;const rd=new FileReader();rd.onload=ev=>{try{mergeNew(parseCSV(ev.target.result));}catch(err){alert('Não consegui ler o CSV. Confira se o arquivo está separado por ponto e vírgula.');console.error(err);}finally{e.target.value='';}};rd.readAsText(f,'utf-8');});
resetBtn.addEventListener('click',()=>{if(confirm('Limpar a base acumulada salva neste navegador e voltar ao anexo inicial?')){clearOldDashboardStorage();localStorage.removeItem(STORAGE_KEY);try{localStorage.removeItem(DEFAULT_FILTER_KEY)}catch(_){}data=applyDataCorrections(INITIAL_DATA);selectedImob='';selectedBarImob='';detail.style.display='none';statusLine.textContent=`Base local reiniciada. Base atual: ${data.length} registros.`;render();}});
render();
